#include "kernel_operator.h"

constexpr int32_t BUFFER_NUM = 2;

class KernelCa6k00236Custom {
public:
    __aicore__ inline KernelCa6k00236Custom() {}

    __aicore__ inline void Init(GM_ADDR x, GM_ADDR y,
                                uint32_t totalCols, uint32_t tileCols,
                                uint32_t height, uint32_t width, int32_t dim)
    {
        totalCols_ = totalCols;
        tileCols_ = tileCols;
        height_ = height;
        width_ = width;
        dim_ = dim;

        xGm_.SetGlobalBuffer((__gm__ float*)x);
        yGm_.SetGlobalBuffer((__gm__ float*)y);

        // Allocate local buffers for one column
        pipe_.InitBuffer(inBuf_, 1, height_ * sizeof(float));
        pipe_.InitBuffer(outBuf_, 1, height_ * sizeof(float));
        pipe_.InitBuffer(expBuf_, 1, height_ * sizeof(float));
        pipe_.InitBuffer(scalarBuf_, 1, sizeof(float));
    }

    __aicore__ inline void Process()
    {
        if (totalCols_ == 0 || tileCols_ == 0) return;

        const uint32_t blockNum = static_cast<uint32_t>(AscendC::GetBlockNum());
        const uint32_t blockIdx = static_cast<uint32_t>(AscendC::GetBlockIdx());

        const uint32_t stride = blockNum * tileCols_;
        uint32_t colStart = blockIdx * tileCols_;
        while (colStart < totalCols_) {
            uint32_t curTileCols = totalCols_ - colStart;
            if (curTileCols > tileCols_) curTileCols = tileCols_;

            for (uint32_t c = 0; c < curTileCols; ++c) {
                uint32_t colIdx = colStart + c;
                ProcessOneColumn(colIdx);
            }

            colStart += stride;
        }
    }

private:
    __aicore__ inline void ProcessOneColumn(uint32_t colIdx)
    {
        // Decompose colIdx into batch and column within that image
        uint32_t batchIdx = colIdx / width_;
        uint32_t localCol = colIdx % width_;

        // Allocate local tensors
        AscendC::LocalTensor<float> xLocal = inBuf_.Get<float>(0, height_);
        AscendC::LocalTensor<float> yLocal = outBuf_.Get<float>(0, height_);
        AscendC::LocalTensor<float> expLocal = expBuf_.Get<float>(0, height_);
        AscendC::LocalTensor<float> scalar = scalarBuf_.Get<float>(0, 1);

        // Load column into xLocal (height elements) using GetValue/SetValue
        for (uint32_t h = 0; h < height_; ++h) {
            uint32_t gmOffset = batchIdx * height_ * width_ + h * width_ + localCol;
            float val = xGm_.GetValue(gmOffset);
            xLocal.SetValue(h, val);
        }

        // y = -x
        AscendC::Muls(yLocal, xLocal, -1.0f, height_);

        // max(y)
        AscendC::ReduceMax(scalar, yLocal, height_);
        // y = y - max
        AscendC::Sub(yLocal, yLocal, scalar, height_);

        // exp(y)
        AscendC::Exp(expLocal, yLocal, height_);

        // sum = sum(exp)
        AscendC::ReduceSum(scalar, expLocal, height_);
        // y = exp / sum
        AscendC::Div(yLocal, expLocal, scalar, height_);

        // Write results to global memory (same layout)
        for (uint32_t h = 0; h < height_; ++h) {
            uint32_t gmOffset = batchIdx * height_ * width_ + h * width_ + localCol;
            float outVal = yLocal.GetValue(h);
            yGm_.SetValue(gmOffset, outVal);
        }

        // Free local tensors
        inBuf_.Free(xLocal);
        outBuf_.Free(yLocal);
        expBuf_.Free(expLocal);
        scalarBuf_.Free(scalar);
    }

private:
    AscendC::TPipe pipe_;
    AscendC::TBuf<AscendC::TPosition::VECCALC> inBuf_;
    AscendC::TBuf<AscendC::TPosition::VECCALC> outBuf_;
    AscendC::TBuf<AscendC::TPosition::VECCALC> expBuf_;
    AscendC::TBuf<AscendC::TPosition::VECCALC> scalarBuf_;

    AscendC::GlobalTensor<float> xGm_;
    AscendC::GlobalTensor<float> yGm_;

    uint32_t totalCols_ {0};
    uint32_t tileCols_ {0};
    uint32_t height_ {0};
    uint32_t width_ {0};
    int32_t dim_ {1};
};

extern "C" __global__ __aicore__ void ca6k_00236_custom(GM_ADDR x, GM_ADDR y, GM_ADDR workspace, GM_ADDR tiling)
{
    GET_TILING_DATA(tiling_data, tiling);
    KernelCa6k00236Custom op;
    op.Init(x, y,
            tiling_data.totalCols,
            tiling_data.tileCols,
            tiling_data.height,
            tiling_data.width,
            tiling_data.dim);
    op.Process();
}
